import os

def get_filenames():
    filenames = []
    while True:
        filename = input('Enter a filename (or END to finish): ')
        if filename == 'END':
            break
        filenames.append(filename)
    return filenames

def get_inputs(filenames):
    inputs = []
    for filename in filenames:
        text = input(f'Enter text for {filename}: ')
        inputs.append((filename, text))
    return inputs

def write_to_file(text, filename):
    with open(filename, 'w') as f:
        f.write(text)

def save_inputs(inputs):
    for filename, text in inputs:
        write_to_file(text, filename)
        os.chmod(filename, 0o777)

def main():
    filenames = get_filenames()
    inputs = get_inputs(filenames)
    save_inputs(inputs)

if __name__ == '__main__':
    main()

